    min_val = min(pixels)
    for i in range(3):
        if pixels[i] == min_val:
            return i

def get_max_key(pixels):
    max_val = max(pixels)
    for i in range(3):
        if pixels[i] == max_val:
            return i

def pixel_fight():
    import sys
    red, green, blue = map(int, sys.stdin.readline().split())
    pixels = [red, green, blue]

    if len(set(pixels)) == 1:
        print(0)
        return

    battles = 0

    while True:
        if len([x for x in pixels if x > 0]) < 2:
            break
        if pixels.count(0) >= 2:
            break

        # Check if two colors have the same count
        if pixels[0] == pixels[1] or pixels[0] == pixels[2] or pixels[1] == pixels[2]:
            break

        # Find the two largest groups
        max1 = get_max_key(pixels)
        temp_pixels = pixels.copy()
        temp_pixels[max1] = -1
        max2 = get_max_key(temp_pixels)

        pixels[max1] -= 1
        pixels[max2] -= 1
        remaining_color = 3 - max1 - max2
        pixels[remaining_color] += 1
        battles += 1

    if len([x for x in pixels if x > 0]) == 1:
        print(battles)
    else:
        # Now, two colors have the same count
        same = []
        diff = -1
        for i in range(3):
            for j in range(i+1, 3):
                if pixels[i] == pixels[j]:
                    same = [i, j]
                    diff = 3 - i - j
        if not same:
            print(-1)
            return

        if pixels[diff] == 0:
            print(-1)
            return

        # The number of battles needed is pixels[diff]
        battles += pixels[diff]
        print(battles)

